//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packagebuildimport("context""fmt""os/exec""regexp""strings""github.com/hashicorp/go-version")//GetGoVersionobtainsversionoflocallyinstalledGovia"goversion"GetGoVersion(ctxcontext.Context)(*version.Version,error){cmd:=exec.CommandContext(ctx,"go","version")out,err:=cmd.CombinedOutput()iferr!=nil{returnnil,fmt.Errorf("unabletobuild:%w\n%s",err,out)}output:=strings.TrimSpace(string(out))//e.g."goversiongo1.15"re:=regexp.MustCompile(`^goversiongo([0-9.]+)\s+`)matches:=re.FindStringSubmatch(output)iflen(matches)!=2{returnnil,fmt.Errorf("unexpectedgoversionoutput:%q",output)}rawGoVersion:=matches[1]v,err:=version.NewVersion(rawGoVersion)iferr!=nil{returnnil,fmt.Errorf("unexpectedgoversionoutput:%w",err)}returnv,nil}